import { useState, useEffect, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  FiSearch, 
  FiAlertCircle, 
  FiFilter, 
  FiGrid, 
  FiList,
  FiStar,
  FiClock,
  FiDollarSign,
  FiTrendingUp,
  FiX,
  FiChevronDown
} from 'react-icons/fi';
import { MenuCardSkeleton } from '../../components/Skeleton/Skeleton';
import { menuAPI, getMediaUrl } from '../../services/api';
import { safeApiCall } from '../../utils/publicApiErrorHandler';
import {
  MenuContainer,
  MenuLayout,
  FilterSidebar,
  MainContent,
  MenuHeader,
  MenuTitle,
  MenuSubtitle,
  MenuControls,
  SearchBar,
  ViewToggle,
  SortDropdown,
  ResultsInfo,
  FilterSection,
  FilterTitle,
  FilterGroup,
  FilterOption,
  PriceRange,
  MenuGrid,
  MenuList,
  NoResults,
  MobileFilterToggle,
  FilterOverlay
} from './Menu.styles';

// Professional Menu Card
const ProfessionalMenuCard = ({ item, isFood = true, index, viewMode = 'grid' }) => {
  const { t } = useTranslation();
  const [imageLoaded, setImageLoaded] = useState(false);

  const imageUrl = getMediaUrl(item.photo);

  const formatPrice = (price) => {
    if (!price) return t('menu.priceOnRequest');
    return new Intl.NumberFormat('uz-UZ').format(price);
  };

  // Category name mapping
  const getCategoryName = (type) => {
    const categoryMap = {
      'appetizers': t('menu.categories.appetizers', 'Appetizers'),
      'soups': t('menu.categories.soups', 'Soups'),
      'salads': t('menu.categories.salads', 'Salads'),
      'main_courses': t('menu.categories.mainCourses', 'Main Courses'),
      'desserts': t('menu.categories.desserts', 'Desserts'),
      'hot_drinks': t('menu.categories.hotDrinks', 'Hot Drinks'),
      'cold_drinks': t('menu.categories.coldDrinks', 'Cold Drinks'),
      'coffee': t('menu.categories.coffee', 'Coffee'),
      'tea': t('menu.categories.tea', 'Tea'),
      'juices': t('menu.categories.juices', 'Juices')
    };
    return categoryMap[type] || type;
  };

  if (viewMode === 'list') {
    return (
      <motion.div
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.3, delay: index * 0.05 }}
        style={{
          display: 'flex',
          backgroundColor: 'white',
          borderRadius: '16px',
          overflow: 'hidden',
          boxShadow: '0 2px 12px rgba(0,0,0,0.08)',
          border: '1px solid rgba(0,0,0,0.06)',
          cursor: 'pointer',
          transition: 'all 0.3s ease',
          marginBottom: '16px',
          minHeight: '140px'
        }}
        whileHover={{ 
          boxShadow: '0 8px 24px rgba(0,0,0,0.12)',
          transform: 'translateY(-2px)'
        }}
      >
        {/* List Image */}
        <div style={{ 
          width: '200px', 
          height: '140px', 
          position: 'relative',
          flexShrink: 0,
          backgroundColor: '#f8fafc'
        }}>
          <img 
            src={imageUrl || '/images/placeholder-menu.svg'}
            alt={item.name}
            style={{
              width: '100%',
              height: '100%',
              objectFit: 'cover',
              opacity: imageLoaded ? 1 : 0,
              transition: 'opacity 0.3s ease'
            }}
            onLoad={() => setImageLoaded(true)}
            onError={(e) => {
              e.target.src = '/images/placeholder-menu.svg';
              setImageLoaded(true);
            }}
          />
        </div>

        {/* List Content */}
        <div style={{ 
          flex: 1, 
          padding: '20px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'space-between'
        }}>
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
              <h3 style={{ 
                fontSize: '1.25rem', 
                fontWeight: '700', 
                color: '#1f2937',
                margin: 0,
                lineHeight: '1.3'
              }}>
                {item.name}
              </h3>
              <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                <div style={{
                  fontSize: '1.5rem',
                  fontWeight: '800',
                  color: '#8B4513'
                }}>
                  {formatPrice(item.price)} {item.price ? 'сум' : ''}
                </div>
              </div>
            </div>

            {isFood && item.ingredients && (
              <p style={{ 
                color: '#6b7280', 
                fontSize: '0.95rem', 
                lineHeight: '1.6',
                margin: '0 0 12px 0',
                display: '-webkit-box',
                WebkitLineClamp: 2,
                WebkitBoxOrient: 'vertical',
                overflow: 'hidden'
              }}>
                {item.ingredients}
              </p>
            )}
          </div>

          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            {/* Nutrition Info */}
            {isFood && (item.calories || item.protein) && (
              <div style={{ display: 'flex', gap: '16px' }}>
                {item.calories && (
                  <div style={{ textAlign: 'center' }}>
                    <div style={{ fontSize: '0.75rem', color: '#8B4513', fontWeight: '600' }}>
                      {t('menu.nutrition.calories', 'Calories')}
                    </div>
                    <div style={{ fontSize: '0.9rem', fontWeight: '700', color: '#1f2937' }}>{item.calories}</div>
                  </div>
                )}
                {item.protein && (
                  <div style={{ textAlign: 'center' }}>
                    <div style={{ fontSize: '0.75rem', color: '#8B4513', fontWeight: '600' }}>
                      {t('menu.nutrition.protein', 'Protein')}
                    </div>
                    <div style={{ fontSize: '0.9rem', fontWeight: '700', color: '#1f2937' }}>{item.protein}g</div>
                  </div>
                )}
              </div>
            )}
          </div>
        </div>
      </motion.div>
    );
  }

  // Grid view (default)
  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4, delay: index * 0.05 }}
      whileHover={{ 
        y: -8,
        transition: { duration: 0.2, ease: "easeOut" }
      }}
      style={{
        backgroundColor: 'white',
        borderRadius: '20px',
        overflow: 'hidden',
        boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
        border: '1px solid rgba(0,0,0,0.06)',
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        width: '100%',
        height: '100%',
        display: 'flex',
        flexDirection: 'column',
        position: 'relative'
      }}
    >
      {/* Image Section */}
      <div style={{ 
        position: 'relative', 
        height: '220px',
        overflow: 'hidden',
        backgroundColor: '#f8fafc'
      }}>
        <img 
          src={imageUrl || '/images/placeholder-menu.svg'}
          alt={item.name}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            transition: 'transform 0.3s ease',
            opacity: imageLoaded ? 1 : 0
          }}
          onLoad={() => setImageLoaded(true)}
          onError={(e) => {
            e.target.src = '/images/placeholder-menu.svg';
            setImageLoaded(true);
          }}
        />

        {/* Category Badge */}
        {item.type && (
          <div style={{
            position: 'absolute',
            top: '16px',
            left: '16px',
            background: 'rgba(139, 69, 19, 0.9)',
            color: 'white',
            padding: '6px 12px',
            borderRadius: '12px',
            fontSize: '0.75rem',
            fontWeight: '600',
            textTransform: 'uppercase',
            letterSpacing: '0.5px',
            backdropFilter: 'blur(8px)'
          }}>
            {getCategoryName(item.type)}
          </div>
        )}

        {/* Rating Badge */}
        <div style={{
          position: 'absolute',
          bottom: '16px',
          left: '16px',
          background: 'rgba(34, 197, 94, 0.9)',
          color: 'white',
          padding: '6px 10px',
          borderRadius: '12px',
          fontSize: '0.8rem',
          fontWeight: '600',
          display: 'flex',
          alignItems: 'center',
          gap: '4px',
          backdropFilter: 'blur(8px)'
        }}>
          <FiStar size={12} fill="currentColor" />
          4.8
        </div>
      </div>

      {/* Content Section */}
      <div style={{ 
        padding: '24px', 
        display: 'flex', 
        flexDirection: 'column', 
        flexGrow: 1,
        gap: '16px'
      }}>
        {/* Title and Price */}
        <div>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
            <h3 style={{ 
              fontSize: '1.3rem', 
              fontWeight: '700', 
              color: '#1f2937',
              lineHeight: '1.3',
              margin: 0,
              flex: 1,
              marginRight: '12px'
            }}>
              {item.name}
            </h3>
            <div style={{
              fontSize: '1.4rem',
              fontWeight: '800',
              color: '#8B4513',
              whiteSpace: 'nowrap'
            }}>
              {formatPrice(item.price)} {item.price ? 'сум' : ''}
            </div>
          </div>

          {/* Description */}
          {isFood && item.ingredients && (
            <p style={{ 
              color: '#6b7280', 
              fontSize: '0.9rem', 
              lineHeight: '1.6',
              margin: 0,
              display: '-webkit-box',
              WebkitLineClamp: 2,
              WebkitBoxOrient: 'vertical',
              overflow: 'hidden'
            }}>
              {t(`menu.ingredients.${item.id}`, item.ingredients)}
            </p>
          )}
        </div>

        {/* Nutrition Info */}
        {isFood && (item.calories || item.protein || item.carbs || item.fats) && (
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(60px, 1fr))',
            gap: '12px',
            padding: '16px',
            backgroundColor: 'rgba(139, 69, 19, 0.05)',
            borderRadius: '12px',
            border: '1px solid rgba(139, 69, 19, 0.1)'
          }}>
            {item.calories && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  КАЛОРИИ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.calories}
                </div>
              </div>
            )}
            {item.protein && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  БЕЛКИ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.protein}г
                </div>
              </div>
            )}
            {item.carbs && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  УГЛЕВОДЫ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.carbs}г
                </div>
              </div>
            )}
            {item.fats && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ЖИРЫ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.fats}г
                </div>
              </div>
            )}
          </div>
        )}

        {/* Beverage Info */}
        {!isFood && (item.volume || item.temperature) && (
          <div style={{
            display: 'flex',
            justifyContent: 'space-around',
            padding: '16px',
            backgroundColor: 'rgba(139, 69, 19, 0.05)',
            borderRadius: '12px',
            border: '1px solid rgba(139, 69, 19, 0.1)'
          }}>
            {item.volume && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ОБЪЕМ
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.volume}мл
                </div>
              </div>
            )}
            {item.temperature && (
              <div style={{ textAlign: 'center' }}>
                <div style={{ fontSize: '0.7rem', color: '#8B4513', fontWeight: '600', marginBottom: '4px' }}>
                  ПОДАЧА
                </div>
                <div style={{ fontSize: '1rem', fontWeight: '700', color: '#1f2937' }}>
                  {item.temperature === 'hot' ? '🔥 Горячий' : 
                   item.temperature === 'cold' ? '❄️ Холодный' : 
                   '🌡️ Любая'}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Add to Cart Button */}
        <motion.button
          whileHover={{ scale: 1.02 }}
          whileTap={{ scale: 0.98 }}
          onClick={handleAddToCart}
          style={{
            background: 'linear-gradient(135deg, #8B4513, #654321)',
            color: 'white',
            border: 'none',
            borderRadius: '16px',
            padding: '14px 20px',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
            fontSize: '1rem',
            fontWeight: '600',
            transition: 'all 0.2s ease',
            boxShadow: '0 4px 12px rgba(139, 69, 19, 0.3)',
            marginTop: 'auto'
          }}
        >
          <FiShoppingCart size={18} />
          Добавить в корзину
        </motion.button>
      </div>
    </motion.div>
  );
};

// Error display component with enhanced recovery options
